// ==========================================
// 📘 JAVASCRIPT EXECUTION CONTEXT
// ==========================================

// JavaScript runs code in 2 phases:
// 1️⃣ Memory Creation Phase
// 2️⃣ Execution Phase


// ==========================================
// 📘 Example Code
// ==========================================

let val1 = 10
let val2 = 5

function addNum(num1, num2){
    let total = num1 + num2
    return total
}

let result1 = addNum(val1, val2)
let result2 = addNum(10, 2)


// ==========================================
// 📘 STEP 1 : Global Execution
// ==========================================

// Global execution context gets created
// this keyword is also allocated


// ==========================================
// 📘 STEP 2 : Memory Creation Phase
// ==========================================

// val1 => undefined
// val2 => undefined
// addNum => function definition
// result1 => undefined
// result2 => undefined


// ==========================================
// 📘 STEP 3 : Execution Phase
// ==========================================

// val1 => 10
// val2 => 5

// First function call creates new execution context
// num1 => 10, num2 => 5, total => 15
// Returns 15 to result1

// Second function call creates new execution context
// num1 => 10, num2 => 2, total => 12
// Returns 12 to result2


// ==========================================
// 📘 CALL STACK EXAMPLE
// ==========================================

function one(){
    console.log("one");
    two()
}

function two(){
    console.log("two");
    three()
}

function three(){
    console.log("three");
}

one()


// ==========================================
// 📘 CALL STACK FLOW
// ==========================================

// one() enters stack
// two() enters stack
// three() enters stack

// three() executes and leaves
// two() executes and leaves
// one() executes and leaves

// Final Output:
// one
two
three
